GUIIllustrationTab = class("GUIIllustrationTab", IGUIWindow)

function GUIIllustrationTab:onLoad()
    self.tabId = 0
    self.isSelect = false

    self.btnTab = self:getChildWindow(0, GUIType.Button)
    self.ivIcon = self:getChildWindow(0, GUIType.StaticImage, self.btnTab)
    self.tvName = self:getChildWindow(0, GUIType.StaticText, self.ivIcon)

    self.btnTab:registerEvent(GUIEvent.ButtonClick, function()
        SoundUtil.clickUI()
        GUIIllustration:onTabClick(self.tabId)
    end)
end

function GUIIllustrationTab:initTab(tab, baseWidth)
    self.tabId = tab.id
    self.baseWidth = baseWidth
    self.ivIcon:SetImage(tab.icon)
    self.tvName:SetText(Lang:getString(tab.name))
    self:changeStatus(tab.isSelect)
end

function GUIIllustrationTab:setSelect()
    if self.isSelect then
        self.root:SetWidth({0, self.baseWidth})
        self.root:SetHeight({0, self.baseWidth * 0.375})
        self.tvName:SetTextColor({30 / 255, 38 / 255, 52 / 255, 1})
        self.btnTab:SetNormalImage("set:lucky_sky_illustrated.json image:tab_select")
        self.btnTab:SetPushedImage("set:lucky_sky_illustrated.json image:tab_select")
    else
        self.root:SetWidth({0, self.baseWidth * 0.8864})
        self.root:SetHeight({0, self.baseWidth * 0.33238})
        self.tvName:SetTextColor({106 / 255, 125 / 255, 145 / 255, 1})
        self.btnTab:SetNormalImage("set:lucky_sky_illustrated.json image:tab_nor")
        self.btnTab:SetPushedImage("set:lucky_sky_illustrated.json image:tab_nor")
    end
end

function GUIIllustrationTab:changeStatus(isSelect)
    self.isSelect = isSelect
    self:setSelect()
end

return GUIIllustrationTab